// frontend/src/components/Dashboard/StatsCards.js
import React, { useState, useEffect, useMemo } from 'react';
import {
  Grid,
  Card,
  CardContent,
  Typography,
  Box,
  Skeleton,
  useTheme,
  CircularProgress,
  Tooltip,
  IconButton,
  LinearProgress
} from '@mui/material';
import {
  TrendingUp,
  TrendingDown,
  AccountBalance,
  ShowChart,
  Timeline,
  Percent,
  Receipt,
  Info,
  CheckCircle,
  Error
} from '@mui/icons-material';
import dashboardService from '../../services/dashboardService';

const StatCard = ({ title, value, secondaryValue, icon, loading, tooltip }) => (
  <Card sx={{ 
    display: 'flex', 
    flexDirection: 'column', 
    justifyContent: 'space-between',
    height: '100%',
    backgroundColor: '#1C2127',
    color: 'white'
  }}>
    <CardContent>
      <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 1 }}>
        <Box sx={{ display: 'flex', alignItems: 'center' }}>
          {icon}
          <Typography variant="subtitle1" component="div" sx={{ ml: 1, fontWeight: 'bold' }}>
            {title}
          </Typography>
        </Box>
        <Tooltip title={tooltip}>
          <IconButton size="small">
            <Info sx={{ color: 'rgba(255, 255, 255, 0.7)' }} />
          </IconButton>
        </Tooltip>
      </Box>
      <Box sx={{ textAlign: 'right', mt: 2 }}>
        {loading ? (
          <CircularProgress size={30} sx={{ color: 'white' }} />
        ) : (
          <>
            <Typography variant="h5" component="div" sx={{ fontWeight: 'bold' }}>
              {value}
            </Typography>
            {secondaryValue && (
              <Typography variant="body2" sx={{ color: 'rgba(255, 255, 255, 0.7)' }}>
                {secondaryValue}
              </Typography>
            )}
          </>
        )}
      </Box>
    </CardContent>
  </Card>
);

const StatsCards = ({ stats, loading, hideValues = false }) => {
  const theme = useTheme();
  const [commissionBalanceUsd, setCommissionBalanceUsd] = useState(0);

  useEffect(() => {
    const updateCommissionBalance = async () => {
      if (stats && stats.operational_balance > 0) {
        try {
          const response = await fetch('https://api.bitget.com/api/v2/spot/market/tickers?symbol=USDTBRL');
          if (!response.ok) {
            throw new Error('Network response was not ok');
          }
          const data = await response.json();
          if (data.code === '00000' && data.data && data.data.length > 0) {
            const brlPrice = parseFloat(data.data[0].lastPr);
            if (brlPrice > 0) {
              const usdValue = stats.operational_balance / brlPrice;
              setCommissionBalanceUsd(usdValue);
            }
          } else {
            setCommissionBalanceUsd(stats.operational_balance * 0.18);
          }
        } catch (error) {
          console.error("Failed to fetch BRL to USD rate:", error);
          setCommissionBalanceUsd(stats.operational_balance * 0.18);
        }
      } else if (stats) {
        setCommissionBalanceUsd(stats.operational_balance_usd || 0);
      }
    };
    updateCommissionBalance();
  }, [stats]);

  const formatCurrency = (value, currency = 'USD') => {
    if (hideValues) return '$***';
    if (value === null || value === undefined) return '$0.00';
    const numValue = parseFloat(value);
    if (Math.abs(numValue) < 0.01 && numValue !== 0) {
      return `$${numValue.toFixed(8)}`;
    }
    if (Math.abs(numValue) < 1) {
      return `$${numValue.toFixed(6)}`;
    }
    return `$${numValue.toFixed(4)}`;
  };

  const formatBrl = (value) => {
    if (hideValues) return 'R$ ***';
    if (value === null || value === undefined) return 'R$ 0,00';
    return Number(value).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  };

  const formatPercentage = (value) => {
    if (value === null || value === undefined) return '0%';
    const decimals = Math.abs(value) < 1 ? 4 : 2;
    return `${value >= 0 ? '+' : ''}${value.toFixed(decimals)}%`;
  };

  const formatNumber = (value) => {
    if (hideValues) return '***';
    if (value === null || value === undefined) return '0';
    return new Intl.NumberFormat('pt-BR').format(value);
  };

  const getColorByValue = (value) => {
    if (value > 0) return theme.palette.success.main;
    if (value < 0) return theme.palette.error.main;
    return theme.palette.text.secondary;
  };

  const statsConfig = [
    {
      title: 'Lucro Aberto',
      value: stats?.unrealized_pnl_percentage,
      format: formatPercentage,
      icon: ShowChart,
      color: getColorByValue(stats?.unrealized_pnl_percentage || 0),
      description: hideValues ? '*** em operações abertas' : `${formatCurrency(stats?.unrealized_pnl || 0)} em operações abertas`
    },
    {
      title: 'PnL Realizado',
      value: stats?.realized_pnl,
      format: formatCurrency,
      icon: Timeline,
      color: getColorByValue(stats?.realized_pnl || 0),
      description: 'Lucro/Prejuízo de trades fechados'
    },
    {
      title: 'Taxa de Acerto',
      value: stats?.win_rate,
      format: formatPercentage,
      icon: TrendingUp,
      color: getColorByValue(stats?.win_rate || 0),
      description: 'Percentual de trades lucrativos'
    },
    {
      title: 'Saldo para Comissão',
      value: commissionBalanceUsd,
      format: formatCurrency,
      secondaryValue: stats?.operational_balance,
      secondaryFormat: formatBrl,
      icon: AccountBalance,
      color: stats?.can_open_positions === false ? theme.palette.error.main : theme.palette.success.main,
      description: stats?.can_open_positions === false 
        ? `🚫 BLOQUEADO - ${formatCurrency(stats?.total_commission_paid_usd || 0)} usado`
        : `Usado: ${formatCurrency(stats?.total_commission_paid_usd || 0)}`,
    },
    {
      title: 'Status da API',
      value: stats?.api_status?.valid ? 'Ativo' : 'Falha',
      format: (value) => value,
      icon: stats?.api_status?.valid ? CheckCircle : Error,
      color: stats?.api_status?.valid ? theme.palette.success.main : theme.palette.error.main,
      description: stats?.api_status?.error_message || 'Conexão com a Bitget funcionando'
    },
  ];

  const operationalBalanceUsd = stats?.operational_balance_usd || 0;
  const operationalBalanceBrl = stats?.operational_balance || 0;

  if (loading) {
    return (
      <Grid container spacing={3}>
        {Array.from({ length: 6 }).map((_, index) => (
          <Grid item xs={12} sm={6} md={4} lg={2} key={index}>
            <Skeleton variant="rectangular" width="100%" height={150} />
          </Grid>
        ))}
      </Grid>
    );
  }

  return (
    <Grid container spacing={3}>
      {statsConfig.map((item, index) => (
        <Grid item xs={12} sm={6} md={4} lg={2.4} key={index}>
          <Card sx={{ height: '100%', display: 'flex', flexDirection: 'column', justifyContent: 'space-between' }}>
            <CardContent>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1 }}>
                <Typography variant="subtitle1" component="div" sx={{ fontWeight: 'bold' }}>
                  {item.title}
                </Typography>
                <Tooltip title={item.description} placement="top">
                  <IconButton size="small">
                    {React.createElement(item.icon, { sx: { color: item.color } })}
                  </IconButton>
                </Tooltip>
              </Box>
              <Box sx={{ textAlign: 'left', mt: 2 }}>
                <Typography variant="h5" component="div" sx={{ fontWeight: 'bold', color: item.color }}>
                  {item.format ? item.format(item.value) : item.value}
                </Typography>
                {item.secondaryValue != null && (
                  <Typography variant="body2" sx={{ color: 'text.secondary', mt: 0.5 }}>
                    {item.secondaryFormat ? item.secondaryFormat(item.secondaryValue) : item.secondaryValue}
                  </Typography>
                )}
              </Box>
            </CardContent>
          </Card>
        </Grid>
      ))}
    </Grid>
  );
};

export default StatsCards;
